<style lang="scss" scoped>
.page-header {
    justify-content: space-between;
    h2 {
        width: auto;
    }
    button {
        padding: 0;
        margin: 0;
        background: none;
        border: none;
    }
}

.user-card__wrapper {
    display: flex;
    align-items: center;
    flex-direction: column;
    margin: 20px 0 40px 0;
    .avatar {
        margin-bottom: 15px;
        width: 120px;
        height: 120px;
        border-radius: 100%;
        overflow: hidden;
        border: 0.5px solid $accent;
        img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            object-position: center;
        }
    }
    h3 {
        margin: 0;
        color: $dark-font;
    }
}

.setting_wrapper {
    display: flex;
    flex-direction: column;
    gap: 10px;
    .setting_wrapper__title {
        font-weight: 400;
        font-size: 12px;
        line-height: 120%;
        text-transform: uppercase;
        color: $grey;
        margin-top: 10px;
        &:first-child {
            margin-top: 0;
        }
    }
    .dual_item {
        box-shadow: 0 3px 10px 0 rgba(37, 37, 37, 0.06);
        border-radius: 12px;
        .setting_wrapper__item {
            box-shadow: none;
            border-radius: 0;
            &:first-child {
                border-top-left-radius: 12px;
                border-top-right-radius: 12px;
            }
            &:last-child {
                border-bottom-left-radius: 12px;
                border-bottom-right-radius: 12px;
            }
        }
    }
    .setting_wrapper__item {
        border-radius: 12px;
        width: 100%;
        box-shadow: 0 3px 10px 0 rgba(37, 37, 37, 0.06);
        padding: 15px 10px;
        background: $home_bg;
        display: flex;
        justify-content: space-between;
        .name {
            display: flex;
            gap: 7px;
            align-items: center;
            font-weight: 400;
            font-size: 14px;
            line-height: 100%;
            color: $dark-font;
            .icon svg {
                width: 12px;
                height: auto;
            }
        }
        .content {
            padding-right: 3px;
            font-weight: 400;
            font-size: 14px;
            line-height: 120%;
            text-align: right;
            color: rgba($dark-font, 0.6);
        }
    }
    .pro_wrapper {
        padding: 15px 10px;
        border-radius: 12px;
        box-shadow: 0 3px 10px 0 rgba(37, 37, 37, 0.06);
        background: $home_bg;
        margin-top: 10px;
        .title {
            font-weight: 500;
            font-size: 20px;
            line-height: 120%;
            color: $dark-font;
            margin-bottom: 10px;
            span {
                display: inline-block;
                padding: 2px 11px;
                font-style: italic;
                font-weight: 700;
                font-size: 20px;
                line-height: 100%;
                letter-spacing: 0.07em;
                text-transform: uppercase;
                color: $light-font;
                border-radius: 22px;
                background: $dark-font;
            }
        }
        p {
            margin-bottom: 20px;
            font-weight: 400;
            font-size: 14px;
            line-height: 120%;
            color: rgba($dark-font, 0.6);
        }
        .button {
            padding: 15px;
            width: 100%;
            font-weight: 500;
            font-size: 16px;
            line-height: 100%;
            color: $light-font;
            display: flex;
            background: $dark-font;
            gap: 5px;
            border-radius: 22px;
            justify-content: center;
        }
    }
    .disabled {
        pointer-events: none;
        position: relative;
        overflow: hidden;
        opacity: 0.4;
        &::before {
            content: '';
            opacity: 0.4;
            background: darkgray;
            position: absolute;
            left: 0;
            top: 0;
            width: 100%;
            height: 100%;
        }
    }
}
</style>